class Solution {
public:
    vector<int> productExceptSelf(vector<int>& nums) {
        int n = nums.size();
        if(n <= 2){
            return nums;
        }

        int* prefix = new int[n];
        int* postfix = new int[n];

        prefix[0] = nums[0];
        postfix[n-1] = nums[n-1];

        for(int i =1; i<n; i++){
            prefix[i] = prefix[i-1] * nums[i];
        }
        for(int i =n-2; i>0; i--){
            postfix[i] = postfix[i+1] * nums[i];
        }

        for(int i =1; i<n-1; i++){
            nums[i] = prefix[i-1] * postfix[i+1];

        }

        nums[0] = postfix[1];
        nums[n-1] = prefix[n-2];

        return nums;


    }
};

